import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = {'requested': p.get('requestedVersion',''), 'resolved': p.get('resolvedVersion','')}
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

print('=== CHANGES ===')
